@dataclasses.dataclass(
    init=True,
    frozen=True,
)
class FileUpload:
    """Class to represent a file upload."""

    upload_id: str | None = None
    on_upload_progress: EventHandler | Callable | None = None
    extra_headers: dict[str, str] | None = None

    @staticmethod
    def on_upload_progress_args_spec(_prog: Var[dict[str, int | float | bool]]):
        """Args spec for on_upload_progress event handler.

        Returns:
            The arg mapping passed to backend event handler
        """
        return [_prog]

    def _as_event_spec(
        self,
        handler: EventHandler,
        *,
        client_handler_name: str,
        upload_param_name: str,
    ) -> EventSpec:
        """Create an upload EventSpec.

        Args:
            handler: The event handler.
            client_handler_name: The client handler name.
            upload_param_name: The upload argument name in the event handler.

        Returns:
            The upload EventSpec.

        Raises:
            ValueError: If the on_upload_progress is not a valid event handler.
        """
        from reflex_components_core.core.upload import (
            DEFAULT_UPLOAD_ID,
            get_upload_files_context_var_data,
        )

        upload_id = self.upload_id if self.upload_id is not None else DEFAULT_UPLOAD_ID
        upload_files_var = Var(
            _js_expr="filesById",
            _var_type=dict[str, Any],
            _var_data=VarData.merge(get_upload_files_context_var_data()),
        ).to(ObjectVar)[LiteralVar.create(upload_id)]
        spec_args = [
            (
                Var(_js_expr="files"),
                upload_files_var,
            ),
            (
                Var(_js_expr="upload_param_name"),
                LiteralVar.create(upload_param_name),
            ),
            (
                Var(_js_expr="upload_id"),
                LiteralVar.create(upload_id),
            ),
            (
                Var(_js_expr="extra_headers"),
                LiteralVar.create(
                    self.extra_headers if self.extra_headers is not None else {}
                ),
            ),
        ]
        if upload_param_name != "files":
            spec_args.insert(
                1,
                (
                    Var(_js_expr=upload_param_name),
                    upload_files_var,
                ),
            )
        if self.on_upload_progress is not None:
            on_upload_progress = self.on_upload_progress
            if isinstance(on_upload_progress, EventHandler):
                events = [
                    call_event_handler(
                        on_upload_progress,
                        self.on_upload_progress_args_spec,
                    ),
                ]
            elif isinstance(on_upload_progress, Callable):
                # Call the lambda to get the event chain.
                events = call_event_fn(
                    on_upload_progress, self.on_upload_progress_args_spec
                )
            else:
                msg = f"{on_upload_progress} is not a valid event handler."
                raise ValueError(msg)
            if isinstance(events, Var):
                msg = f"{on_upload_progress} cannot return a var {events}."
                raise ValueError(msg)
            on_upload_progress_chain = EventChain(
                events=[*events],
                args_spec=self.on_upload_progress_args_spec,
            )
            formatted_chain = str(format.format_prop(on_upload_progress_chain))
            spec_args.append(
                (
                    Var(_js_expr="on_upload_progress"),
                    FunctionStringVar(
                        formatted_chain.strip("{}"),
                    ).to(FunctionVar, EventChain),
                ),
            )
        return EventSpec(
            handler=handler,
            client_handler_name=client_handler_name,
            args=tuple(spec_args),
            event_actions=handler.event_actions.copy(),
        )

    def as_event_spec(self, handler: EventHandler) -> EventSpec:
        """Get the EventSpec for the file upload.

        Args:
            handler: The event handler.

        Returns:
            The event spec for the handler.
        """
        from reflex_base.utils.exceptions import UploadValueError

        try:
            upload_param_name, _annotation = resolve_upload_handler_param(handler)
        except UploadValueError:
            upload_param_name = "files"
        return self._as_event_spec(
            handler,
            client_handler_name=UPLOAD_FILES_CLIENT_HANDLER,
            upload_param_name=upload_param_name,
        )
